    , MonthlyCost = ((BillableGB / daysInRange) * 30.0) * priceAnalytics
| order by BillableGB desc
| take 50
| project DataType
    , Solution
    , ['GB (window)']=round(BillableGB,2)
    , ['GB/day']=round(DailyAvgGB,2)
    , ['GB/month']=round(MonthlyGB,2)
    , ['Analytics cost/month ({Currency})']=round(MonthlyCost,2)

set truncationmaxrecords=10000;
set truncationmaxsize=67108864;
let daysInRange = toreal({TimeRange:seconds}) / 86400.0;
let userRate = toreal('{EffectiveAnalyticsRate}');
let modelRate = case('{PricingModel}' == 'CT50', 3.23, '{PricingModel}' == 'CT100', 2.96, '{PricingModel}' == 'CT200', 2.85, '{PricingModel}' == 'CT300', 2.77, '{PricingModel}' == 'CT400', 2.73, '{PricingModel}' == 'CT500', 2.61, '{PricingModel}' == 'CT1000', 2.41, '{PricingModel}' == 'CT2000', 2.22, '{PricingModel}' == 'CT5000', 2.11, 4.30);
let priceAnalytics = iif(userRate > 0, userRate, modelRate);
let priceLakeIngest = toreal('{LakeIngestPricePerGB}');
let priceLakeProc = toreal('{LakeProcessingPricePerGB}');
let priceLakeStore = toreal('{LakeStoragePricePerGBMonth}');
let lakeRetentionDays = toreal('{TargetLakeRetentionDays}');
let compressionRatio = toreal('{CompressionRatio}');
let incompatibleTables = dynamic([
    'AzureDiagnostics'
]);
let systemTables = dynamic([
    'Heartbeat','Usage','Operation','LAQueryLogs','SecurityAlert','SecurityIncident'
    ,'ProtectionStatus','ComputerGroup'
]);
let lakeCandidates = dynamic([
    'CommonSecurityLog','Syslog','W3CIISLog'
    ,'AADNonInteractiveUserSignInLogs','AADServicePrincipalSignInLogs','AADManagedIdentitySignInLogs'
    ,'DnsEvents','WindowsFirewall','Perf'
    ,'UniFiFlowLog_CL','UniFiDHCP_CL','UniFiVPN_CL','UniFiWANFailover_CL'
]);
Usage
| where TimeGenerated {TimeRange}
| where IsBillable == true
| summarize BillableGB = sum(Quantity) / 1000.0 by DataType
| extend MonthlyGB = (BillableGB / daysInRange) * 30.0
| extend AnalyticsMonthlyCost = MonthlyGB * priceAnalytics
| extend LakeIngestCost = MonthlyGB * priceLakeIngest
    , LakeProcCost = MonthlyGB * priceLakeProc
    , LakeStorageCost = (MonthlyGB * (lakeRetentionDays / 30.0) / compressionRatio) * priceLakeStore
| extend LakeMonthlyCost = LakeIngestCost + LakeProcCost + LakeStorageCost
| extend MonthlySaving = AnalyticsMonthlyCost - LakeMonthlyCost
    , SavingPct = iif(AnalyticsMonthlyCost > 0, round((AnalyticsMonthlyCost - LakeMonthlyCost) / AnalyticsMonthlyCost * 100.0, 1), real(0))
| extend IsIncompatible = DataType in (incompatibleTables)
    , IsSystem = DataType in (systemTables)
| extend Candidate = case(
    IsIncompatible, '🚫 Not lake-compatible'
    , IsSystem, '🔧 System table (skip)'
    , DataType in (lakeCandidates), '✅ Verbose/low-fidelity'
    , DataType endswith '_CL', '🟢 Custom log (verify V1 vs DCR)'
    , '⚠️ Review detection impact first')
// Null out lake costs and savings for incompatible tables — they physically can't be moved
| extend LakeMonthlyCost = iif(IsIncompatible, real(null), LakeMonthlyCost)
    , MonthlySaving = iif(IsIncompatible, real(null), MonthlySaving)
    , SavingPct = iif(IsIncompatible, real(null), SavingPct)
| order by MonthlySaving desc nulls last
| project Table=DataType
    , Candidate
    , GBPerMonth=round(MonthlyGB,2)
    , AnalyticsCost=round(AnalyticsMonthlyCost,2)
    , LakeCost=round(LakeMonthlyCost,2)
    , MonthlySaving=round(MonthlySaving,2)
    , SavingPct

